        "content": "#!/usr/bin/env bash\nset -euo pipefail\n\nAPI_URL=\"${CHATGPT_IMAGE_API_URL:-https://chatgpt-image.vyibc.com}\"\nIMAGE=\"\"\nIMAGE_URL=\"\"\nPROMPT=\"\"\nUPLOAD_NAME=\"\"\nPOLL_INTERVAL=\"${CHATGPT_IMAGE_POLL_INTERVAL:-5}\"\nTIMEOUT_SECONDS=\"${CHATGPT_IMAGE_TIMEOUT_SECONDS:-300}\"\nTMP_DIR=\"\"\n\ncleanup() {\n  if [[ -n \"$TMP_DIR\" && -d \"$TMP_DIR\" ]]; then\n    rm -rf \"$TMP_DIR\"\n  fi\n}\ntrap cleanup EXIT\n\nprint_health_summary() {\n  local label=\"${1:-Browser workers}\"\n  local health_json\n  health_json=\"$(curl -sS \"${API_URL%/}/health\" || true)\"\n  HEALTH_JSON=\"$health_json\" python3 - \"$label\" <<'PY' 2>/dev/null || true\nimport json\nimport os\nimport sys\n\nlabel = sys.argv[1]\ndata = json.loads(os.environ.get(\"HEALTH_JSON\") or \"{}\")\nworkers = data.get(\"workers\") or []\ntotal = len(workers)\nlogged_in = sum(1 for worker in workers if worker.get(\"loginState\") == \"logged_in\" and not worker.get(\"loginRequired\"))\nlogin_required = sum(1 for worker in workers if worker.get(\"loginRequired\"))\nactive = sum(1 for worker in workers if worker.get(\"active\"))\nunknown = total - logged_in - login_required\nqueued = data.get(\"queued\", 0)\nports = \",\".join(str(worker.get(\"cdpPort\", \"\")) for worker in workers)\n\nprint(\n    f\"{label}: total={total} loggedIn={logged_in} \"\n    f\"loginRequired={login_required} unknown={unknown} active={active} queued={queued} ports={ports}\",\n    file=sys.stderr,\n)\n\nif login_required:\n    login_url = data.get(\"loginUrl\") or \"\"\n    if login_url:\n        print(\"Open this browser URL and log in:\", file=sys.stderr)\n        print(login_url, file=sys.stderr)\nPY\n}\n\nusage() {\n  cat >&2 <<'USAGE'\nUsage:\n  chatgpt-remote-image.sh --prompt \"...\" [--imageUrl https://.../ref.png] [--image /path/to/ref.png] [--uploadName result.png]\n\nEnvironment:\n  CHATGPT_IMAGE_API_URL     Default: https://chatgpt-image.vyibc.com\nUSAGE\n}\n\nwhile [[ $# -gt 0 ]]; do\n  case \"$1\" 